import Link from "next/link";
import { getTranslations } from "next-intl/server";
import { AppShell } from "@/components/app-shell";
import { getAuthContext } from "@/lib/firebase/auth";
import { boardsRepository } from "@/lib/repositories/boards-repository";
import { knowledgeRepository } from "@/lib/repositories/knowledge-repository";
import { skillsRepository } from "@/lib/repositories/skills-repository";

export default async function Page() {
  const common = await getTranslations("Common");
  const t = await getTranslations("Dashboard");
  const shell = await getTranslations("Shell");
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell section="dashboard"><p>{common("unauthenticated")}</p></AppShell>;
  }

  const [boards, knowledge, skills] = await Promise.all([
    boardsRepository.list(auth.workspaceId),
    knowledgeRepository.list(auth.workspaceId),
    skillsRepository.list(auth.workspaceId),
  ]);

  return (
    <AppShell section="dashboard">
      <div className="content-stack space-y-6">
        <section className="stat-grid">
          <article className="app-card"><p className="eyebrow">{t("boardItems")}</p><p className="stat-value">{boards.length}</p></article>
          <article className="app-card"><p className="eyebrow">{t("knowledgeEntries")}</p><p className="stat-value">{knowledge.length}</p></article>
          <article className="app-card"><p className="eyebrow">{t("skills")}</p><p className="stat-value">{skills.length}</p></article>
        </section>
        <section className="app-card">
          <h2 className="mb-3 font-semibold">{t("quickAccess")}</h2>
          <div className="quick-links">
            <Link href="/board" className="pill-link">{shell("nav.board")}</Link>
            <Link href="/knowledge" className="pill-link">{shell("nav.knowledge")}</Link>
            <Link href="/skills" className="pill-link">{shell("nav.skills")}</Link>
          </div>
        </section>
        <section className="two-column">
          <article className="app-card">
            <h2 className="mb-3 font-semibold">{t("recentActivity")}</h2>
            {boards.slice(0, 4).map((item) => (
              <p key={item.id} className="text-sm muted">{item.title}</p>
            ))}
            {boards.length === 0 ? <p className="text-sm muted">{t("noRecentActivity")}</p> : null}
          </article>
          <article className="app-card">
            <h2 className="mb-3 font-semibold">{t("topSkills")}</h2>
            {skills.slice(0, 5).map((skill) => (
              <span key={skill.id} className="tag-pill">{skill.name}</span>
            ))}
            {skills.length === 0 ? <p className="text-sm muted">{t("noSkills")}</p> : null}
          </article>
        </section>
      </div>
    </AppShell>
  );
}
